import { useRegistryTheme } from '../../lib/theme';
import * as React from 'react';
import { Animated, Pressable, StyleSheet, type PressableProps } from 'react-native';

type SwitchProps = Omit<PressableProps, 'onChange'> & {
    checked?: boolean;
