import * as React from 'react';
import {
    PanResponder,
    StyleSheet,
    View,
    type GestureResponderEvent,
    type LayoutChangeEvent,
    type ViewProps,
} from 'react-native';
import { useRegistryTheme } from '../../lib/theme';

type SliderProps = ViewProps & {
    defaultValue?: number;
    value?: number;
    min?: number;
    max?: number;
    step?: number;
    disabled?: boolean;
    onValueChange?: (value: number) => void;
};

function clamp(value: number, min: number, max: number) {
    return Math.min(Math.max(value, min), max);
}

function snap(value: number, step: number, min: number) {
    return Math.round((value - min) / step) * step + min;
}

function Slider({
    defaultValue,
    value,
    min = 0,
    max = 100,
    step = 1,
    disabled = false,
    onValueChange,
    style,
    ...props
}: SliderProps) {
    const theme = useRegistryTheme();
    const trackRef = React.useRef<View>(null);
    const [trackMetrics, setTrackMetrics] = React.useState({ x: 0, width: 1 });
    const [internalValue, setInternalValue] = React.useState(defaultValue ?? min);
    const isControlled = value !== undefined;
    const resolvedValue = clamp(isControlled ? value : internalValue, min, max);

    const updateValue = React.useCallback(
        (nextValue: number) => {
            const clamped = clamp(snap(nextValue, step, min), min, max);

            if (!isControlled) {
                setInternalValue(clamped);
            }

            onValueChange?.(clamped);
        },
        [isControlled, max, min, onValueChange, step],
    );

    const syncTrackMetrics = React.useCallback(() => {
        trackRef.current?.measureInWindow((x, _y, width) => {
            setTrackMetrics({
                x,
                width: Math.max(width, 1),
            });
        });
    }, []);

    const updateFromEvent = React.useCallback(
        (event: GestureResponderEvent, pointerX?: number) => {
            if (disabled) {
                return;
            }

            const absoluteX = pointerX ?? event.nativeEvent.pageX;
            const ratio = clamp(
                (absoluteX - trackMetrics.x) / trackMetrics.width,
                0,
                1,
            );
            updateValue(min + ratio * (max - min));
        },
        [disabled, max, min, trackMetrics.width, trackMetrics.x, updateValue],
    );

    const responder = React.useMemo(
        () =>
            PanResponder.create({
                onStartShouldSetPanResponder: () => !disabled,
                onMoveShouldSetPanResponder: () => !disabled,
                onPanResponderGrant: (event) => {
                    syncTrackMetrics();
                    updateFromEvent(event);
                },
                onPanResponderMove: (event, gestureState) => {
                    updateFromEvent(event, gestureState.moveX);
                },
            }),
        [disabled, syncTrackMetrics, updateFromEvent],
    );

    const percentage = ((resolvedValue - min) / (max - min || 1)) * 100;

    const handleLayout = React.useCallback((event: LayoutChangeEvent) => {
        setTrackMetrics((current) => ({
            ...current,
            width: Math.max(event.nativeEvent.layout.width, 1),
        }));
        requestAnimationFrame(syncTrackMetrics);
    }, [syncTrackMetrics]);

    return (
        <View
            style={[styles.root, disabled ? styles.disabled : null, style]}
            {...props}
        >
            <View
                ref={trackRef}
                onLayout={handleLayout}
                style={[styles.track, { backgroundColor: theme.secondary }]}
                {...responder.panHandlers}
            >
                <View
                    style={[
                        styles.range,
                        { width: `${percentage}%`, backgroundColor: theme.primary },
                    ]}
                />
                <View
                    style={[
                        styles.thumb,
                        {
                            left: `${percentage}%`,
                            borderColor: theme.border,
                            backgroundColor: theme.background,
                        },
                    ]}
                />
            </View>
        </View>
    );
}

const styles = StyleSheet.create({
    root: {
        width: '100%',
        justifyContent: 'center',
        paddingVertical: 10,
    },
    track: {
        width: '100%',
        height: 8,
        borderRadius: 999,
        justifyContent: 'center',
    },
    range: {
        position: 'absolute',
        left: 0,
        height: 8,
        borderRadius: 999,
    },
    thumb: {
        position: 'absolute',
        width: 20,
        height: 20,
        marginLeft: -10,
        borderRadius: 999,
        borderWidth: 1,
        shadowColor: '#000',
        shadowOffset: { width: 0, height: 1 },
        shadowOpacity: 0.08,
        shadowRadius: 6,
        elevation: 1,
    },
    disabled: {
        opacity: 0.45,
    },
});

export { Slider };
export type { SliderProps };

import * as React from 'react';
import {
    Pressable,
    StyleSheet,
    View,
    type PressableProps,
    type TextProps,
    type ViewProps,
} from 'react-native';
import { Text } from './text';

type TooltipContextValue = {
    open: boolean;
    setOpen: React.Dispatch<React.SetStateAction<boolean>>;
};

type TooltipProps = {
    children?: React.ReactNode;
    defaultOpen?: boolean;
    open?: boolean;
    onOpenChange?: (open: boolean) => void;
};

type TooltipTriggerProps = PressableProps & {
    asChild?: boolean;
    children?: React.ReactNode;
};

type TooltipContentProps = ViewProps & {
    children?: React.ReactNode;
};

const TooltipContext = React.createContext<TooltipContextValue | null>(null);

function useTooltipContext() {
    const context = React.useContext(TooltipContext);

    if (!context) {
        throw new Error('Tooltip components must be used inside Tooltip.');
    }

    return context;
}

function Tooltip({
    children,
    defaultOpen = false,
    open,
    onOpenChange,
}: TooltipProps) {
    const [internalOpen, setInternalOpen] = React.useState(defaultOpen);
    const isControlled = open !== undefined;
    const resolvedOpen = isControlled ? open : internalOpen;

    const setOpen = React.useCallback<React.Dispatch<React.SetStateAction<boolean>>>(
        (value) => {
            const nextValue =
                typeof value === 'function' ? value(resolvedOpen) : value;

            if (!isControlled) {
                setInternalOpen(nextValue);
            }

            onOpenChange?.(nextValue);
        },
        [isControlled, onOpenChange, resolvedOpen],
    );

    return (
        <TooltipContext.Provider value={{ open: resolvedOpen, setOpen }}>
            <View style={styles.root}>{children}</View>
        </TooltipContext.Provider>
    );
}

function TooltipProvider({ children }: { children?: React.ReactNode }) {
    return <>{children}</>;
}

function TooltipTrigger({
    asChild = false,
    children,
    onLongPress,
    onPressIn,
    onPressOut,
    ...props
}: TooltipTriggerProps) {
    const { setOpen } = useTooltipContext();

    const handleLongPress = React.useCallback(
        (event: Parameters<NonNullable<PressableProps['onLongPress']>>[0]) => {
            onLongPress?.(event);
            setOpen(true);
        },
        [onLongPress, setOpen],
    );

    const handlePressIn = React.useCallback(
        (event: Parameters<NonNullable<PressableProps['onPressIn']>>[0]) => {
            onPressIn?.(event);
            setOpen(true);
        },
        [onPressIn, setOpen],
    );

    const handlePressOut = React.useCallback(
        (event: Parameters<NonNullable<PressableProps['onPressOut']>>[0]) => {
            onPressOut?.(event);
            setOpen(false);
        },
        [onPressOut, setOpen],
    );

    if (asChild && React.isValidElement(children)) {
        return React.cloneElement(
            children as React.ReactElement<{
                onLongPress?: PressableProps['onLongPress'];
                onPressIn?: PressableProps['onPressIn'];
                onPressOut?: PressableProps['onPressOut'];
            }>,
            {
                onLongPress: handleLongPress,
                onPressIn: handlePressIn,
                onPressOut: handlePressOut,
            },
        );
    }

    return (
        <Pressable
            onLongPress={handleLongPress}
            onPressIn={handlePressIn}
            onPressOut={handlePressOut}
            {...props}
        >
            {children}
        </Pressable>
    );
}

function TooltipContent({ children, style, ...props }: TooltipContentProps) {
    const { open } = useTooltipContext();

    if (!open) {
        return null;
    }

    return (
        <View style={[styles.content, style]} {...props}>
            {children}
        </View>
    );
}

function TooltipText({ style, ...props }: TextProps) {
    return <Text style={[styles.text, style]} {...props} />;
}

const styles = StyleSheet.create({
    root: {
        alignSelf: 'flex-start',
    },
    content: {
        position: 'absolute',
        top: '100%',
        left: '50%',
        marginTop: 8,
        minWidth: 120,
        marginLeft: -60,
        borderRadius: 10,
        backgroundColor: '#09090b',
        paddingHorizontal: 10,
        paddingVertical: 8,
    },
    text: {
        color: '#fafafa',
        fontSize: 12,
        lineHeight: 16,
    },
});

export {
    Tooltip,
    TooltipContent,
    TooltipProvider,
    TooltipText,
    TooltipTrigger,
};
export type { TooltipContentProps, TooltipProps, TooltipTriggerProps };

import { useEffect, useMemo, useRef } from "react";
import {
  Animated,
  Easing,
  Pressable,
  StyleSheet,
  View,
  type PressableProps,
  type StyleProp,
  type ViewStyle,
} from "react-native";

import { Colors } from "@/constants/theme";
import { useColorScheme } from "@/hooks/use-color-scheme";
import { Text } from "@/components/ui/text";

type SpotlightButtonVariant = "default" | "neutral";
type SpotlightButtonSize = "default" | "lg";

type SpotlightButtonProps = Omit<PressableProps, "children"> & {
  badge?: string;
  children: React.ReactNode;
  variant?: SpotlightButtonVariant;
  size?: SpotlightButtonSize;
};

function getPalette(theme: "light" | "dark", variant: SpotlightButtonVariant) {
  if (variant === "neutral") {
    return theme === "dark"
      ? {
          background: "#18181b",
          border: "rgba(255,255,255,0.10)",
          text: "#f4f4f5",
          badgeBackground: "rgba(255,255,255,0.08)",
          badgeBorder: "rgba(255,255,255,0.14)",
          badgeText: "#d4d4d8",
          glow: "rgba(255,255,255,0.12)",
          shadow: "rgba(0,0,0,0.45)",
        }
      : {
          background: "#ffffff",
          border: "rgba(15,23,42,0.10)",
          text: "#111827",
          badgeBackground: "rgba(15,23,42,0.05)",
          badgeBorder: "rgba(15,23,42,0.08)",
          badgeText: "#475569",
          glow: "rgba(59,130,246,0.14)",
          shadow: "rgba(15,23,42,0.14)",
        };
  }

  return theme === "dark"
    ? {
        background: "#60a5fa",
        border: "rgba(191,219,254,0.45)",
        text: "#08111f",
        badgeBackground: "rgba(255,255,255,0.30)",
        badgeBorder: "rgba(255,255,255,0.35)",
        badgeText: "#0f172a",
        glow: "rgba(96,165,250,0.34)",
        shadow: "rgba(37,99,235,0.34)",
      }
    : {
        background: Colors.light.tint,
        border: "rgba(125,211,252,0.45)",
        text: "#eff6ff",
        badgeBackground: "rgba(255,255,255,0.18)",
        badgeBorder: "rgba(255,255,255,0.22)",
        badgeText: "#e0f2fe",
        glow: "rgba(14,165,233,0.24)",
        shadow: "rgba(14,165,233,0.28)",
      };
}

function getContainerStyle(size: SpotlightButtonSize): StyleProp<ViewStyle> {
  if (size === "lg") return styles.containerLg;
  return styles.containerDefault;
}

export function SpotlightButton({
  badge = "New",
  children,
  variant = "default",
  size = "default",
  style,
  ...props
}: SpotlightButtonProps) {
  const theme = useColorScheme() ?? "light";
  const shimmerX = useRef(new Animated.Value(-220)).current;
  const glowPulse = useRef(new Animated.Value(0.88)).current;
  const palette = useMemo(() => getPalette(theme, variant), [theme, variant]);

  useEffect(() => {
    const shimmerLoop = Animated.loop(
      Animated.timing(shimmerX, {
        toValue: 220,
        duration: 2600,
        easing: Easing.linear,
        useNativeDriver: true,
      }),
    );

    const glowLoop = Animated.loop(
      Animated.sequence([
        Animated.timing(glowPulse, {
          toValue: 1.06,
          duration: 1400,
          easing: Easing.inOut(Easing.ease),
          useNativeDriver: true,
        }),
        Animated.timing(glowPulse, {
          toValue: 0.88,
          duration: 1400,
          easing: Easing.inOut(Easing.ease),
          useNativeDriver: true,
        }),
      ]),
    );

    shimmerLoop.start();
    glowLoop.start();

    return () => {
      shimmerLoop.stop();
      glowLoop.stop();
    };
  }, [glowPulse, shimmerX]);

  return (
    <Pressable
      accessibilityRole="button"
      {...props}
      style={(state) => {
        const { pressed } = state;
        const resolvedStyle =
          typeof style === "function" ? style(state) : style;

        return [
          styles.wrapper,
          {
            transform: [{ scale: pressed ? 0.985 : 1 }],
            opacity: props.disabled ? 0.55 : 1,
          },
          resolvedStyle,
        ];
      }}
    >
      {({ pressed }) => (
        <View
          style={[
            styles.containerBase,
            getContainerStyle(size),
            {
              backgroundColor: palette.background,
              borderColor: palette.border,
              shadowColor: palette.shadow,
            },
            pressed && styles.containerPressed,
          ]}
        >
          <Animated.View
            pointerEvents="none"
            style={[
              styles.glow,
              {
                backgroundColor: palette.glow,
                transform: [{ scale: glowPulse }],
              },
            ]}
          />
          <Animated.View
            pointerEvents="none"
            style={[
              styles.shimmer,
              {
                transform: [{ translateX: shimmerX }, { rotate: "16deg" }],
              },
            ]}
          />
          <View
            style={[
              styles.badge,
              {
                backgroundColor: palette.badgeBackground,
                borderColor: palette.badgeBorder,
              },
            ]}
          >
            <Text style={[styles.badgeText, { color: palette.badgeText }]}>
              {badge}
            </Text>
          </View>
          <View style={styles.labelRow}>
            <Text style={[styles.labelText, { color: palette.text }]}>
              {children}
            </Text>
            <Text style={[styles.arrow, { color: palette.text }]}>→</Text>
          </View>
        </View>
      )}
    </Pressable>
  );
}

